THEME_COLORS = {'bg': '#1E1F22', 'panel': '#2B2D31', 'teal': '#0F7F6E', 'primary': '#0F7F6E', 'teal_hover': '#149682', 'text_main': '#E6E8EB', 'text_dim': '#949BA4', 'border': '#3F4148', 'success': '#00C853', 'danger': '#FF5252'}
STYLESHEET = f"\n    QMainWindow, QDialog {{\n        background-color: {THEME_COLORS['bg']};\n        color: {THEME_COLORS['text_main']};\n    }}\n    QWidget {{\n        font-family: 'Segoe UI', 'Roboto', sans-serif;\n        font-size: 13px;\n        color: {THEME_COLORS['text_main']};\n    }}\n    /* --- GROUPS & FRAMES --- */\n    QGroupBox {{\n        border: 1px solid {THEME_COLORS['border']};\n        border-radius: 4px;\n        margin-top: 24px;\n        padding-top: 15px;\n        font-weight: bold;\n        text-transform: uppercase;\n        letter-spacing: 1px;\n        color: {THEME_COLORS['text_dim']};\n    }}\n    QGroupBox::title {{\n        subcontrol-origin: margin;\n        subcontrol-position: top left;\n        padding: 0 5px;\n        left: 10px;\n    }}\n    QScrollArea {{\n        border: none;\n        background-color: {THEME_COLORS['bg']};\n    }}\n    \n    /* --- BUTTONS --- */\n    QPushButton {{\n        background-color: transparent;\n        border: 1px solid {THEME_COLORS['border']};\n        border-radius: 4px;\n        color: {THEME_COLORS['text_main']};\n        padding: 8px 16px;\n        font-weight: 600;\n        letter-spacing: 0.5px;\n    }}\n    QPushButton:hover {{\n        border-color: {THEME_COLORS['teal']};\n        background-color: rgba(15, 127, 110, 0.1);\n    }}\n    QPushButton:disabled {{\n        border-color: #333;\n        color: #555;\n    }}\n    \n    /* --- SLIDERS --- */\n    QSlider::groove:horizontal {{\n        border: 1px solid {THEME_COLORS['border']};\n        height: 4px;\n        background: #111;\n        margin: 2px 0;\n        border-radius: 2px;\n    }}\n    QSlider::handle:horizontal {{\n        background: {THEME_COLORS['teal']};\n        border: 1px solid {THEME_COLORS['teal']};\n        width: 14px;\n        height: 14px;\n        margin: -6px 0;\n        border-radius: 7px;\n    }}\n    \n    /* --- TABS --- */\n    QTabWidget::pane {{ \n        border: 1px solid {THEME_COLORS['border']}; \n        background: {THEME_COLORS['panel']};\n    }}\n    QTabBar::tab {{\n        background: {THEME_COLORS['bg']};\n        color: {THEME_COLORS['text_dim']};\n        padding: 10px 20px;\n        border-bottom: 2px solid transparent;\n        text-transform: uppercase;\n        font-size: 11px;\n        letter-spacing: 1px;\n    }}\n    QTabBar::tab:selected {{\n        color: {THEME_COLORS['teal']};\n        border-bottom: 2px solid {THEME_COLORS['teal']};\n        background: {THEME_COLORS['panel']};\n    }}\n    \n    /* --- RADIO BUTTONS --- */\n    QRadioButton {{ spacing: 8px; color: {THEME_COLORS['text_main']}; }}\n    QRadioButton::indicator {{ width: 14px; height: 14px; }}\n    QRadioButton::indicator:checked {{\n        background-color: {THEME_COLORS['teal']};\n        border: 2px solid {THEME_COLORS['bg']};\n        border-radius: 7px;\n        outline: 1px solid {THEME_COLORS['teal']};\n    }}\n    QRadioButton::indicator:unchecked {{\n        background-color: transparent;\n        border: 1px solid {THEME_COLORS['text_dim']};\n        border-radius: 7px;\n    }}\n"